 33‚Üípublic class SiteUtils {
 34‚Üí    public static final String GB_EDITOR_NAME = "gutenberg";
 35‚Üí    public static final String AZTEC_EDITOR_NAME = "aztec";
 36‚Üí    public static final String WP_STORIES_CREATOR_NAME = "wp_stories_creator";
 37‚Üí    public static final String WP_STORIES_JETPACK_VERSION = "9.1";
 38‚Üí    public static final String WP_CONTACT_INFO_JETPACK_VERSION = "8.5";
 39‚Üí    public static final String WP_FACEBOOK_EMBED_JETPACK_VERSION = "9.0";
 40‚Üí    public static final String WP_INSTAGRAM_EMBED_JETPACK_VERSION = "9.0";
 41‚Üí    public static final String WP_LOOM_EMBED_JETPACK_VERSION = "9.0";
 42‚Üí    public static final String WP_SMARTFRAME_EMBED_JETPACK_VERSION = "10.2";
 43‚Üí    private static final int GB_ROLLOUT_PERCENTAGE_PHASE_1 = 100;
 44‚Üí    private static final int GB_ROLLOUT_PERCENTAGE_PHASE_2 = 100;
 45‚Üí
 46‚Üí    /**
 47‚Üí     * Migrate the old app-wide editor preference value to per-site setting. wpcom sites will make a network call
 48‚Üí     * and store the value on the backend. selfHosted sites just store the value in the local DB in FluxC
 49‚Üí     * <p>
 50‚Üí     * Strategy: Check if there is the old app-wide preference still available (v12.9 and before used it).
 51‚Üí     * -- 12.9 ON -> turn all sites ON in 13.0
 52‚Üí     * -- 12.9 OPTED OUT (were auto-opted in but turned it OFF) -> turn all sites OFF in 13.0
 53‚Üí     */
 54‚Üí    public static void migrateAppWideMobileEditorPreferenceToRemote(final AccountStore accountStore,
 55‚Üí                                                                    final SiteStore siteStore,
 56‚Üí                                                                    final Dispatcher dispatcher) {
 57‚Üí        // Skip if the user is not signed in
 58‚Üí        if (!FluxCUtils.isSignedInWPComOrHasWPOrgSite(accountStore, siteStore)) {
 59‚Üí            return;
 60‚Üí        }
 61‚Üí
 62‚Üí        // If the user is already in the rollout group, we can skip this the migration.
 63‚Üí        if (AppPrefs.isUserInGutenbergRolloutGroup()) {
 64‚Üí            return;
 65‚Üí        }
 66‚Üí
 67‚Üí        // -------- Rollout: Phase 2 -------
 68‚Üí        //
 69‚Üí        // If user has any Aztec enabled sites, we'll migrate their sites to Gutenberg and schedule showing popup.
 70‚Üí        if (atLeastOneSiteHasAztecEnabled(siteStore)) {
 71‚Üí            // Randomly pick the user in the rollout group
 72‚Üí            if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_2)) {
 73‚Üí                if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
 74‚Üí                    // If the network is not available, abort. We can't update the remote setting.
 75‚Üí                    return;
 76‚Üí                }
 77‚Üí
 78‚Üí                for (SiteModel site : siteStore.getSites()) {
 79‚Üí                    // Show "phase 2" dialog on sites that get switched from aztec to gutenberg
 80‚Üí                    if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
 81‚Üí                        AppPrefs.setShowGutenbergInfoPopupPhase2ForNewPosts(site.getUrl(), true);
 82‚Üí                        // Will show the popup again, even if it was displayed in the past
 83‚Üí                        AppPrefs.setGutenbergInfoPopupDisplayed(site.getUrl(), false);
 84‚Üí                        continue;
 85‚Üí                    }
 86‚Üí
 87‚Üí                    // Show "phase 1" dialog on sites that get switched from "empty" (no pref) to gutenberg
 88‚Üí                    if (TextUtils.isEmpty(site.getMobileEditor())) {
 89‚Üí                        AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
 90‚Üí                    }
 91‚Üí                }
 92‚Üí
 93‚Üí                // Track and enable Gutenberg for all sites using a single network call. Ideally we would track this
 94‚Üí                // on the network response, but this would make this rollout even more complex.
 95‚Üí                // There might be some rare events when we register a site switched to Gutenberg which is actually
 96‚Üí                // still on Aztec.
 97‚Üí                trackGutenbergEnabledForNonGutenbergSites(siteStore,
 98‚Üí                        BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_2);
 99‚Üí                dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
100‚Üí                        new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME, false)));
101‚Üí
102‚Üí                // After enabling Gutenberg on these sites, we consider the user entered the rollout group
103‚Üí                AppPrefs.setUserInGutenbergRolloutGroup();
104‚Üí            }
105‚Üí        }
106‚Üí
107‚Üí        // -------- Rollout: Phase 1 -------
108‚Üí        //
109‚Üí        // Check if the user has been "randomly" selected to enter the rollout group.
110‚Üí        //
111‚Üí        // For self hosted sites, there are often one or two users, and the user id is probably 0, 1 in these cases.
112‚Üí        // If we exclude low ids, we won't get an not an homogeneous distribution over self hosted and WordPress.com
113‚Üí        // users, but the purpose of this is to do a progressive rollout, not an necessarily an homogeneous rollout.
114‚Üí        //
115‚Üí        // To exclude ids 0 and 1, to rollout for 10% users,
116‚Üí        // we'll use a test like `id % 100 >= 90` instead of `id % 100 < 10`.
117‚Üí        if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_1)) {
118‚Üí            if (atLeastOneSiteHasAztecEnabled(siteStore)) {
119‚Üí                // If the user has opt-ed out from at least one of their site, then exclude them from the cohort
120‚Üí                return;
121‚Üí            }
122‚Üí
123‚Üí            if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
124‚Üí                // If the network is not available, abort. We can't update the remote setting.
125‚Üí                return;
126‚Üí            }
127‚Üí
128‚Üí            // Force the dialog to be shown on updated sites
129‚Üí            for (SiteModel site : siteStore.getSites()) {
130‚Üí                if (TextUtils.isEmpty(site.getMobileEditor())) {
131‚Üí                    AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
132‚Üí                }
133‚Üí            }
134‚Üí
135‚Üí            // Track and enable and  Gutenberg for all sites using a single network call. Ideally we would track this
136‚Üí            // on the network response, but this would make this rollout even more complex.
137‚Üí            // There might be some rare events when we register a site switched to Gutenberg which is actually
138‚Üí            // still on Aztec.
139‚Üí            trackGutenbergEnabledForNonGutenbergSites(siteStore,
140‚Üí                    BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_1);
141‚Üí            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
142‚Üí                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
143‚Üí
144‚Üí            // After enabling Gutenberg on these sites, we consider the user entered the rollout group
145‚Üí            AppPrefs.setUserInGutenbergRolloutGroup();
146‚Üí        }
147‚Üí
148‚Üí        if (!AppPrefs.isDefaultAppWideEditorPreferenceSet()) {
149‚Üí            return;
150‚Üí        }
151‚Üí        final boolean oldAppWidePreferenceValue = AppPrefs.isGutenbergDefaultForNewPosts();
152‚Üí
153‚Üí        if (oldAppWidePreferenceValue) {
154‚Üí            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
155‚Üí                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
156‚Üí        } else {
157‚Üí            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
158‚Üí                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.AZTEC_EDITOR_NAME)));
159‚Üí        }
160‚Üí    }
