162‚Üí    private static void trackGutenbergEnabledForNonGutenbergSites(final SiteStore siteStore,
163‚Üí                                                                  final BlockEditorEnabledSource source) {
164‚Üí        for (SiteModel site : siteStore.getSites()) {
165‚Üí            if (!TextUtils.equals(site.getMobileEditor(), GB_EDITOR_NAME)) {
166‚Üí                AnalyticsUtils.trackWithSiteDetails(Stat.EDITOR_GUTENBERG_ENABLED, site, source.asPropertyMap());
167‚Üí            }
168‚Üí        }
169‚Üí    }
