171‚Üí    private static boolean atLeastOneSiteHasAztecEnabled(final SiteStore siteStore) {
172‚Üí        // We want to make sure to enable Gutenberg only on the sites they didn't opt-out.
173‚Üí        for (SiteModel site : siteStore.getSites()) {
174‚Üí            if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
175‚Üí                return true;
176‚Üí            }
177‚Üí        }
178‚Üí        return false;
179‚Üí    }
