181‚Üí    public static boolean enableBlockEditorOnSiteCreation(Dispatcher dispatcher, SiteStore siteStore,
182‚Üí                                                          int siteLocalSiteID) {
183‚Üí        SiteModel newSiteModel = siteStore.getSiteByLocalId(siteLocalSiteID);
184‚Üí        if (newSiteModel != null) {
185‚Üí            enableBlockEditor(dispatcher, newSiteModel);
186‚Üí            AnalyticsUtils.trackWithSiteDetails(Stat.EDITOR_GUTENBERG_ENABLED, newSiteModel,
187‚Üí                    BlockEditorEnabledSource.ON_SITE_CREATION.asPropertyMap());
188‚Üí            return true;
189‚Üí        }
190‚Üí        return false;
191‚Üí    }
