203‚Üí    public static boolean isBlockEditorDefaultForNewPost(@Nullable SiteModel site) {
204‚Üí        if (site == null) {
205‚Üí            return true;
206‚Üí        }
207‚Üí        if (TextUtils.isEmpty(site.getMobileEditor())) {
208‚Üí            // Default to block editor when mobile editor setting is empty
209‚Üí            return true;
210‚Üí        } else {
211‚Üí            return alwaysDefaultToGutenberg(site) || site.getMobileEditor().equals(SiteUtils.GB_EDITOR_NAME);
212‚Üí        }
213‚Üí    }
