219‚Üí    public static String getSiteNameOrHomeURL(SiteModel site) {
220‚Üí        String siteName = site.getName();
221‚Üí        if (siteName == null) {
222‚Üí            return "";
223‚Üí        }
224‚Üí        if (siteName.trim().length() == 0) {
225‚Üí            siteName = getHomeURLOrHostName(site);
226‚Üí        }
227‚Üí        return siteName;
228‚Üí    }
