230‚Üí    public static String getHomeURLOrHostName(SiteModel site) {
231‚Üí        String homeURL = UrlUtils.removeScheme(site.getUrl());
232‚Üí        homeURL = StringUtils.removeTrailingSlash(homeURL);
233‚Üí        if (TextUtils.isEmpty(homeURL)) {
234‚Üí            return UrlUtils.getHost(site.getXmlRpcUrl());
235‚Üí        }
236‚Üí        return homeURL;
237‚Üí    }
