255‚Üí    public static ImageType getSiteImageType(boolean isP2, BlavatarShape shape) {
256‚Üí        ImageType type = ImageType.BLAVATAR;
257‚Üí        if (isP2) {
258‚Üí            switch (shape) {
259‚Üí                case SQUARE:
260‚Üí                    type = ImageType.P2_BLAVATAR;
261‚Üí                    break;
262‚Üí                case SQUARE_WITH_ROUNDED_CORNERES:
263‚Üí                    type = ImageType.P2_BLAVATAR_ROUNDED_CORNERS;
264‚Üí                    break;
265‚Üí                case CIRCULAR:
266‚Üí                    type = ImageType.P2_BLAVATAR_CIRCULAR;
267‚Üí                    break;
268‚Üí            }
269‚Üí        } else {
270‚Üí            switch (shape) {
271‚Üí                case SQUARE:
272‚Üí                    type = ImageType.BLAVATAR;
273‚Üí                    break;
274‚Üí                case SQUARE_WITH_ROUNDED_CORNERES:
275‚Üí                    type = ImageType.BLAVATAR_ROUNDED_CORNERS;
276‚Üí                    break;
277‚Üí                case CIRCULAR:
278‚Üí                    type = ImageType.BLAVATAR_CIRCULAR;
279‚Üí                    break;
280‚Üí            }
281‚Üí        }
282‚Üí        return type;
283‚Üí    }
