285‚Üí    public static SiteAccessibilityInfo getAccessibilityInfoFromSite(@NonNull SiteModel site) {
286‚Üí        SiteVisibility siteVisibility;
287‚Üí
288‚Üí        if (site.isPrivateWPComAtomic()) {
289‚Üí            siteVisibility = SiteVisibility.PRIVATE_ATOMIC;
290‚Üí        } else if (site.isPrivate()) {
291‚Üí            siteVisibility = SiteVisibility.PRIVATE;
292‚Üí        } else {
293‚Üí            siteVisibility = SiteVisibility.PUBLIC;
294‚Üí        }
295‚Üí
296‚Üí        return new SiteAccessibilityInfo(siteVisibility, isPhotonCapable(site));
297‚Üí    }
