309‚Üí    /**
310‚Üí     * Checks if site Jetpack version is higher than limit version
311‚Üí     *
312‚Üí     * @param site
313‚Üí     * @param limitVersion minimal acceptable Jetpack version
314‚Üí     * @return
315‚Üí     */
316‚Üí    public static boolean checkMinimalJetpackVersion(SiteModel site, String limitVersion) {
317‚Üí        String jetpackVersion = site.getJetpackVersion();
318‚Üí        if (site.isUsingWpComRestApi() && site.isJetpackConnected() && !TextUtils.isEmpty(jetpackVersion)) {
319‚Üí            // Jetpack version field is sometimes "false" instead of a number on self-hosted sites that are no
320‚Üí            // longer active.
321‚Üí            if (jetpackVersion.equals("false")) {
322‚Üí                return false;
323‚Üí            }
324‚Üí            return VersionUtils.checkMinimalVersion(jetpackVersion, limitVersion);
325‚Üí        }
326‚Üí        return false;
327‚Üí    }
