101‚Üí    fun onResume(jetpackSocialFlow: JetpackSocialFlow) {
102‚Üí        _jetpackSocialUiState.value?.let { uiState ->
103‚Üí            if (uiState is JetpackSocialUiState.Loaded && uiState.showShareLimitUi) {
104‚Üí                jetpackSocialSharingTracker.trackShareLimitDisplayed(jetpackSocialFlow)
105‚Üí            } else if (uiState is JetpackSocialUiState.NoConnections) {
106‚Üí                trackAddConnectionCtaDisplayedIfVisible(jetpackSocialFlow)
107‚Üí            }
108‚Üí        }
109‚Üí        if (!isLastActionOnResumeHandled) {
110‚Üí            isLastActionOnResumeHandled = true
111‚Üí            when (actionEvents.value) {
112‚Üí                is ActionEvent.OpenSocialConnectionsList -> {
