120‚Üí
121‚Üí                is ActionEvent.OpenSubscribeJetpackSocial -> {
122‚Üí                    // We have to update SiteModel to make sure we have the latest data regarding user hired plans
123‚Üí                    dispatcher.dispatch(SiteActionBuilder.newFetchSiteAction(siteModel))
124‚Üí                }
125‚Üí
126‚Üí                else -> {
127‚Üí                    // Do nothing
128‚Üí                }
129‚Üí            }
130‚Üí        }
131‚Üí    }
