133‚Üí    private suspend fun loadConnections() {
134‚Üí        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
135‚Üí            siteId = siteModel.siteId,
136‚Üí            userId = accountStore.account.userId
137‚Üí        )
138‚Üí        connections.clear()
139‚Üí        connections.addAll(publicizeConnections.map { connection ->
140‚Üí            PostSocialConnection.fromPublicizeConnection(connection, false)
141‚Üí        })
142‚Üí        updateInitialConnectionListSharingStatus()
143‚Üí    }
