145‚Üí    private suspend fun updateConnections() {
146‚Üí        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
147‚Üí            siteId = siteModel.siteId,
148‚Üí            userId = accountStore.account.userId,
149‚Üí            shouldForceUpdate = false,
150‚Üí        )
151‚Üí        // Update connections list with new connections
152‚Üí        val currentConnectionIds = connections.map { it.connectionId }
153‚Üí        publicizeConnections.forEach { publicizeConnection ->
154‚Üí            if (currentConnectionIds.doesNotContain(publicizeConnection.connectionId)) {
155‚Üí                connections.add(PostSocialConnection.fromPublicizeConnection(publicizeConnection, false))
156‚Üí            }
157‚Üí        }
158‚Üí        // Update connections list with removed connections
159‚Üí        currentConnectionIds.forEach { currentConnectionId ->
160‚Üí            if (publicizeConnections.map { connection -> connection.connectionId }
161‚Üí                    .doesNotContain(currentConnectionId)) {
162‚Üí                connections.removeAll { connection -> connection.connectionId == currentConnectionId }
163‚Üí            }
164‚Üí        }
165‚Üí    }
