167‚Üí    private suspend fun loadJetpackSocialIfSupported() {
168‚Üí        if (!shouldShowJetpackSocial()) {
169‚Üí            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_HIDDEN)
170‚Üí            return
171‚Üí        }
172‚Üí
173‚Üí        if (showNoConnections()) {
174‚Üí            // If user previously dismissed the no connections container by tapping the "Not now" button,
175‚Üí            // we should hide the container.
176‚Üí            _jetpackSocialContainerVisibility.postValue(getJetpackSocialContainerVisibilityFromPrefs())
177‚Üí
178‚Üí            _jetpackSocialUiState.postValue(
