215‚Üí    private fun updateInitialConnectionListSharingStatus() {
216‚Üí        if (isPostPublished()) {
217‚Üí            connections.map { it.isSharingEnabled = false }
218‚Üí            return
219‚Üí        }
220‚Üí        val shareLimitValue = shareLimit
221‚Üí        val skipConnections = postPublicizeSkipConnections()
222‚Üí        if (shareLimitValue is ShareLimit.Enabled) {
223‚Üí            // If shares remaining < number of connections, all connections are unchecked by default
224‚Üí            updateInitialConnectionListShareLimitEnabled(shareLimitValue, skipConnections)
225‚Üí        } else {
226‚Üí            updateInitialConnectionListShareLimitDisabled(skipConnections)
227‚Üí        }
228‚Üí    }
229‚Üí
230‚Üí    private fun updateInitialConnectionListShareLimitEnabled(
231‚Üí        shareLimitValue: ShareLimit.Enabled,
232‚Üí        skipConnections: List<PublicizeSkipConnection>
233‚Üí    ) {
234‚Üí        if (shareLimitValue.sharesRemaining < connections.size) {
235‚Üí            connections.map { it.isSharingEnabled = false }
236‚Üí        } else {
237‚Üí            connections.take(shareLimitValue.sharesRemaining).map {
238‚Üí                it.isSharingEnabled = true
239‚Üí            }
240‚Üí            connections.forEach { connection ->
241‚Üí                // Use metadata to verify if this connection was previously disabled by the user
242‚Üí                skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
243‚Üí                    ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
244‚Üí            }
245‚Üí        }
246‚Üí    }
247‚Üí
248‚Üí    private fun updateInitialConnectionListShareLimitDisabled(skipConnections: List<PublicizeSkipConnection>) {
249‚Üí        // With share limit disabled we can enable all connections but still considering the skip
250‚Üí        // connections metadata
251‚Üí        connections.map { it.isSharingEnabled = true }
252‚Üí        connections.forEach { connection ->
253‚Üí            // Use metadata to verify if this connection was previously disabled by the user
254‚Üí            skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
255‚Üí                ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
256‚Üí        }
257‚Üí    }
