294‚Üí    @VisibleForTesting
295‚Üí    fun onJetpackSocialConnectionClick(
296‚Üí        connection: PostSocialConnection,
297‚Üí        enabled: Boolean,
298‚Üí        jetpackSocialFlow: JetpackSocialFlow
299‚Üí    ) {
300‚Üí        jetpackSocialSharingTracker.trackConnectionToggled(jetpackSocialFlow, enabled)
301‚Üí        launch {
302‚Üí            // Update UI
303‚Üí            connections.firstOrNull { it.connectionId == connection.connectionId }?.let {
304‚Üí                it.isSharingEnabled = enabled
305‚Üí            }
306‚Üí            _jetpackSocialUiState.postValue(mapLoaded())
307‚Üí            // Update local post
308‚Üí            editPostRepository.updateAsync({ postModel ->
309‚Üí                val connectionId = connection.connectionId.toString()
310‚Üí                with(postModel.publicizeSkipConnectionsList.toMutableList()) {
311‚Üí                    firstOrNull { it.connectionId() == connectionId }?.updateValue(enabled)
312‚Üí                        ?: run {
313‚Üí                            // Connection wasn't part of skip connections before, so we must add it
314‚Üí                            // with the correct value
315‚Üí                            add(PublicizeSkipConnection.createNew(connectionId, enabled))
316‚Üí                        }
317‚Üí                    postModel.updatePublicizeSkipConnections(this)
318‚Üí                }
319‚Üí                true
320‚Üí            })
321‚Üí        }
