 39‚Üíclass EditorJetpackSocialViewModel @Inject constructor(
 40‚Üí    private val dispatcher: Dispatcher,
 41‚Üí    private val accountStore: AccountStore,
 42‚Üí    private val getPublicizeConnectionsForUserUseCase: GetPublicizeConnectionsForUserUseCase,
