 52‚Üí) : ScopedViewModel(bgDispatcher) {
 53‚Üí    private lateinit var siteModel: SiteModel
 54‚Üí    private lateinit var editPostRepository: EditPostRepository
 55‚Üí
 56‚Üí    private val _jetpackSocialContainerVisibility = MutableLiveData<JetpackSocialContainerVisibility>()
 57‚Üí    val jetpackSocialContainerVisibility: LiveData<JetpackSocialContainerVisibility> = _jetpackSocialContainerVisibility
 58‚Üí
 59‚Üí    private val _jetpackSocialUiState = MutableLiveData<JetpackSocialUiState>()
 60‚Üí    val jetpackSocialUiState: LiveData<JetpackSocialUiState> = _jetpackSocialUiState
 61‚Üí
 62‚Üí    // this is a SingleLiveEvent so it should have one, and only one, observer (the Activity)
 63‚Üí    private val _actionEvents = SingleLiveEvent<ActionEvent>()
 64‚Üí    val actionEvents: LiveData<ActionEvent> = _actionEvents
 65‚Üí
 66‚Üí    private var jetpackSocialShareMessage = ""
