 74‚Üí    private val currentPost: PostImmutableModel?
 75‚Üí        get() = editPostRepository.getPost()
 76‚Üí
 77‚Üí    fun start(siteModel: SiteModel, editPostRepository: EditPostRepository) {
 78‚Üí        if (isStarted) return
 79‚Üí
 80‚Üí        dispatcher.register(this)
 81‚Üí
 82‚Üí        isStarted = true
 83‚Üí        this.siteModel = siteModel
 84‚Üí        this.editPostRepository = editPostRepository
 85‚Üí
 86‚Üí        startJetpackSocial()
 87‚Üí    }
