 89‚Üí    private fun startJetpackSocial() {
 90‚Üí        if (shouldShowJetpackSocial()) {
 91‚Üí            launch {
 92‚Üí                shareLimit = getJetpackSocialShareLimitStatusUseCase.execute(siteModel)
 93‚Üí                loadConnections()
 94‚Üí                loadJetpackSocialIfSupported()
 95‚Üí            }
 96‚Üí        } else {
 97‚Üí            _jetpackSocialContainerVisibility.value = JetpackSocialContainerVisibility.ALL_HIDDEN
 98‚Üí        }
 99‚Üí    }
100‚Üí
101‚Üí    fun onResume(jetpackSocialFlow: JetpackSocialFlow) {
102‚Üí        _jetpackSocialUiState.value?.let { uiState ->
103‚Üí            if (uiState is JetpackSocialUiState.Loaded && uiState.showShareLimitUi) {
104‚Üí                jetpackSocialSharingTracker.trackShareLimitDisplayed(jetpackSocialFlow)
105‚Üí            } else if (uiState is JetpackSocialUiState.NoConnections) {
106‚Üí                trackAddConnectionCtaDisplayedIfVisible(jetpackSocialFlow)
107‚Üí            }
108‚Üí        }
109‚Üí        if (!isLastActionOnResumeHandled) {
110‚Üí            isLastActionOnResumeHandled = true
111‚Üí            when (actionEvents.value) {
112‚Üí                is ActionEvent.OpenSocialConnectionsList -> {
113‚Üí                    // When getting back from publicize connections screen, we should update connections to
114‚Üí                    // make sure we have the latest data.
115‚Üí                    launch {
116‚Üí                        updateConnections()
117‚Üí                        loadJetpackSocialIfSupported()
118‚Üí                    }
119‚Üí                }
120‚Üí
121‚Üí                is ActionEvent.OpenSubscribeJetpackSocial -> {
122‚Üí                    // We have to update SiteModel to make sure we have the latest data regarding user hired plans
123‚Üí                    dispatcher.dispatch(SiteActionBuilder.newFetchSiteAction(siteModel))
124‚Üí                }
125‚Üí
126‚Üí                else -> {
127‚Üí                    // Do nothing
128‚Üí                }
129‚Üí            }
130‚Üí        }
131‚Üí    }
132‚Üí
133‚Üí    private suspend fun loadConnections() {
134‚Üí        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
135‚Üí            siteId = siteModel.siteId,
136‚Üí            userId = accountStore.account.userId
137‚Üí        )
138‚Üí        connections.clear()
139‚Üí        connections.addAll(publicizeConnections.map { connection ->
140‚Üí            PostSocialConnection.fromPublicizeConnection(connection, false)
141‚Üí        })
142‚Üí        updateInitialConnectionListSharingStatus()
143‚Üí    }
144‚Üí
145‚Üí    private suspend fun updateConnections() {
146‚Üí        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
147‚Üí            siteId = siteModel.siteId,
148‚Üí            userId = accountStore.account.userId,
149‚Üí            shouldForceUpdate = false,
150‚Üí        )
151‚Üí        // Update connections list with new connections
152‚Üí        val currentConnectionIds = connections.map { it.connectionId }
153‚Üí        publicizeConnections.forEach { publicizeConnection ->
154‚Üí            if (currentConnectionIds.doesNotContain(publicizeConnection.connectionId)) {
155‚Üí                connections.add(PostSocialConnection.fromPublicizeConnection(publicizeConnection, false))
156‚Üí            }
157‚Üí        }
158‚Üí        // Update connections list with removed connections
159‚Üí        currentConnectionIds.forEach { currentConnectionId ->
160‚Üí            if (publicizeConnections.map { connection -> connection.connectionId }
161‚Üí                    .doesNotContain(currentConnectionId)) {
162‚Üí                connections.removeAll { connection -> connection.connectionId == currentConnectionId }
163‚Üí            }
164‚Üí        }
165‚Üí    }
166‚Üí
167‚Üí    private suspend fun loadJetpackSocialIfSupported() {
168‚Üí        if (!shouldShowJetpackSocial()) {
169‚Üí            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_HIDDEN)
170‚Üí            return
171‚Üí        }
172‚Üí
173‚Üí        if (showNoConnections()) {
174‚Üí            // If user previously dismissed the no connections container by tapping the "Not now" button,
175‚Üí            // we should hide the container.
176‚Üí            _jetpackSocialContainerVisibility.postValue(getJetpackSocialContainerVisibilityFromPrefs())
177‚Üí
178‚Üí            _jetpackSocialUiState.postValue(
179‚Üí                jetpackUiStateMapper.mapNoConnections(
180‚Üí                    ::onJetpackSocialConnectProfilesClick,
181‚Üí                    ::onJetpackSocialNotNowClick
182‚Üí                )
183‚Üí            )
184‚Üí        } else {
185‚Üí            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_VISIBLE)
186‚Üí            _jetpackSocialUiState.postValue(mapLoaded())
187‚Üí        }
188‚Üí    }
189‚Üí
190‚Üí    private fun shouldShowJetpackSocial() = !editPostRepository.isPage
191‚Üí            && siteModel.supportsPublicize()
192‚Üí            && currentPost?.status != PostStatus.PRIVATE.toString()
193‚Üí
194‚Üí    private suspend fun mapLoaded(): JetpackSocialUiState.Loaded {
195‚Üí        val shareMessage = jetpackSocialShareMessage.ifEmpty {
196‚Üí            getJetpackSocialShareMessageUseCase.execute(currentPost?.id ?: -1)
197‚Üí        }
198‚Üí        val socialSharingModel = postSocialSharingModelMapper.map(connections, shareLimit)
199‚Üí        return jetpackUiStateMapper.mapLoaded(
200‚Üí            connections = connections,
201‚Üí            shareLimit = shareLimit,
202‚Üí            socialSharingModel = socialSharingModel,
203‚Üí            onSubscribeClick = ::onJetpackSocialSubscribeClick,
204‚Üí            shareMessage = shareMessage,
205‚Üí            onShareMessageClick = ::onJetpackSocialMessageClick,
206‚Üí            onConnectionClick = ::onJetpackSocialConnectionClick,
207‚Üí            isPostPublished = isPostPublished(),
208‚Üí        )
209‚Üí    }
210‚Üí
211‚Üí    private fun showNoConnections(): Boolean =
212‚Üí        connections.isEmpty()
213‚Üí                && publicizeTableWrapper.getServiceList().any { it.status != PublicizeService.Status.UNSUPPORTED }
214‚Üí
215‚Üí    private fun updateInitialConnectionListSharingStatus() {
216‚Üí        if (isPostPublished()) {
217‚Üí            connections.map { it.isSharingEnabled = false }
218‚Üí            return
219‚Üí        }
220‚Üí        val shareLimitValue = shareLimit
221‚Üí        val skipConnections = postPublicizeSkipConnections()
222‚Üí        if (shareLimitValue is ShareLimit.Enabled) {
223‚Üí            // If shares remaining < number of connections, all connections are unchecked by default
224‚Üí            updateInitialConnectionListShareLimitEnabled(shareLimitValue, skipConnections)
225‚Üí        } else {
226‚Üí            updateInitialConnectionListShareLimitDisabled(skipConnections)
227‚Üí        }
228‚Üí    }
229‚Üí
230‚Üí    private fun updateInitialConnectionListShareLimitEnabled(
231‚Üí        shareLimitValue: ShareLimit.Enabled,
232‚Üí        skipConnections: List<PublicizeSkipConnection>
233‚Üí    ) {
234‚Üí        if (shareLimitValue.sharesRemaining < connections.size) {
235‚Üí            connections.map { it.isSharingEnabled = false }
236‚Üí        } else {
237‚Üí            connections.take(shareLimitValue.sharesRemaining).map {
238‚Üí                it.isSharingEnabled = true
239‚Üí            }
240‚Üí            connections.forEach { connection ->
241‚Üí                // Use metadata to verify if this connection was previously disabled by the user
242‚Üí                skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
243‚Üí                    ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
244‚Üí            }
245‚Üí        }
246‚Üí    }
247‚Üí
248‚Üí    private fun updateInitialConnectionListShareLimitDisabled(skipConnections: List<PublicizeSkipConnection>) {
249‚Üí        // With share limit disabled we can enable all connections but still considering the skip
250‚Üí        // connections metadata
251‚Üí        connections.map { it.isSharingEnabled = true }
252‚Üí        connections.forEach { connection ->
253‚Üí            // Use metadata to verify if this connection was previously disabled by the user
254‚Üí            skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
255‚Üí                ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
256‚Üí        }
257‚Üí    }
